  ('social-worker-moex-04079', 'social-worker', 'social-worker-moex-111-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '有關社會工作者於高齡者照顧機構的工作與角色，下列何者正確？①說明與推動病人自主權', '["擬定與執行長者入住適應計劃", "組織機構長輩，擔任社區獨居長者電話問安工作， 提供長輩自我實現機會", "社會工作者在與家屬討論、說明醫療約束評估的過程中，並無角 色功能", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:23+00:00", "source_pdf_sha1": "05188af2adcc", "answer_pdf_sha1": "aea6905a7961", "source_family": "moex-gov-tw", "moex": {"exam_code": "111110", "c": "105", "s": "0401", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作", "year": "111", "exam_name": "111年第二次專技人員高等考試中醫師考試分階段考試、營養師、護理師、社會工作師考試、111年專技人員高等考試法醫師、語言治療師、聽力師、牙體...", "original_question_number": 33, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL)
